def login_view(request):
    limit = rate_limiter(request.client_ip)
    if not limit.ok:
        return HttpResponse(status=429)
    creds = parse_credentials(request)
    return _dispatch(creds)

def rate_limiter(ip):
    window = store.incr(f"rl:{ip}", ttl=60)
    return Limit(ok=window < 10, remaining=10 - window)

def validate_input(creds):
    if len(creds.password) < 8:
        raise ValidationError("password too short")
    if not USERNAME_RE.match(creds.username):
        raise ValidationError("bad username")
    return creds

def verify_password(pw, stored):
    try:
        return hasher.verify(stored, pw)
    except VerifyMismatchError:
        return False
